def Fval(r,p,a,h):
    lam=p/(1-p)
    return (1 if r>=p else 0) - lam*(1 if r < p-a else 0) + p*(1 if (p-h <= r < p) else 0) + lam*p*(1 if (p-a-h <= r < p-a) else 0)
def check_point(p,a,h,y):
    xs=sorted(set([-1,0,p-a-h-y,p-a-h,p-a-y,p-a,p-h-y,p-h,p-y,p,1,1-a-h-y,1-a-h]))
    # sample midpoints and exact thresholds maybe
    samples=[]
    for u,v in zip(xs,xs[1:]):
        samples.append((u+v)/2)
    samples+=xs
    mn=1e9; bad=[]
    for r in samples:
        G=(1-p)*Fval(r,p,a,h)+p*Fval(r+y,p,a,h)
        H=Fval(r,p,a,h+y)
        diff=G-H
        if diff<mn: mn=diff
        if diff<-1e-9: bad.append((r,G,H,diff))
    return mn,bad[:5]
