def test_schur(b,a,tries=10000):
    for _ in range(tries):
        x=np.random.dirichlet(np.ones(b))
        i,j=np.random.choice(b,2,replace=False)
        if x[i]<x[j]: i,j=j,i
        delta=np.random.rand()*x[j]
        y=x.copy(); y[i]+=delta; y[j]-=delta
        c1=good_count(x,a); c2=good_count(y,a)
        if c2>c1:
            return x,y,c1,c2,(i,j,delta)
    return None
