def tail_prob(weights,p):
    # compute exact by DP over subset sums for m up to maybe 20 via dict
    dist={0.0:1.0}
    for w in weights:
        nd={}
        for s,prob in dist.items():
            nd[s]=nd.get(s,0)+prob*(1-p)
            nd[s+w]=nd.get(s+w,0)+prob*p
        dist=nd
    return sum(prob for s,prob in dist.items() if s>=p-1e-12)

def tail_prob_arr(weights,p):
    m=len(weights)
    prob=0.0
    for mask in range(1<<m):
        s=0; k=0
        for i,w in enumerate(weights):
            if mask>>i&1:
                s+=w; k+=1
        if s>=p-1e-12:
            prob+=p**k*(1-p)**(m-k)
    return prob

def random_search(p,m,N=10000,alpha=0.3):
    best=(1,None)
    for _ in range(N):
        # mixture Dirichlet with small alpha and perturb near pivot
        if np.random.rand()<0.2:
            eps=10**np.random.uniform(-4,-1)*p
            w=np.concatenate([[p-eps], np.random.dirichlet(np.ones(m-1))* (1-p+eps)])
            np.random.shuffle(w)
        else:
            w=np.random.dirichlet(np.ones(m)*alpha)
        val=tail_prob(w,p)
        if val<best[0]:
            best=(val,w)
    return best
